define <8 x float> @widen_extract4(<8 x float> %ins, <2 x float> %ext) {
  %e1 = extractelement <2 x float> %ext, i32 0
  %i1 = insertelement <8 x float> %ins, float %e1, i32 2
  ret <8 x float> %i1
}

define <8 x float> @widen_extract4(<8 x float> %ins, <2 x float> %ext) {
  %e1 = extractelement <2 x float> %ext, i32 0
  %i1 = insertelement <8 x float> %ins, float %e1, i32 2
  ret <8 x float> %i1
}

define <2 x i1> @PR40734(<1 x i1> %x, <4 x i1> %y) {
  %widen = shufflevector <1 x i1> zeroinitializer, <1 x i1> %x, <2 x i32> <i32 0, i32 1>
  %narrow = shufflevector <4 x i1> %y, <4 x i1> poison, <2 x i32> <i32 0, i32 1>
  %r = and <2 x i1> %widen, %narrow
  ret <2 x i1> %r
}

define <2 x float> @frem_splat_constant1(<2 x float> %x) {
  %splat = shufflevector <2 x float> %x, <2 x float> poison, <2 x i32> zeroinitializer
  %r = frem <2 x float> %splat, <float 4.200000e+01, float 4.200000e+01>
  ret <2 x float> %r
}

define <2 x i1> @PR40734(<1 x i1> %x, <4 x i1> %y) {
  %widen = shufflevector <1 x i1> zeroinitializer, <1 x i1> %x, <2 x i32> <i32 0, i32 1>
  %narrow = shufflevector <4 x i1> %y, <4 x i1> undef, <2 x i32> <i32 0, i32 1>
  %r = and <2 x i1> %widen, %narrow
  ret <2 x i1> %r
}

define <4 x i16> @blend_elements_from_load(ptr align 8 %_0) {
  %load = load <3 x i16>, ptr %_0, align 8
  %rv = shufflevector <3 x i16> <i16 0, i16 undef, i16 undef>, <3 x i16> %load, <4 x i32> <i32 0, i32 1, i32 3, i32 5>
  ret <4 x i16> %rv
}

define <2 x float> @frem_splat_constant1(<2 x float> %x) {
  %splat = shufflevector <2 x float> %x, <2 x float> undef, <2 x i32> zeroinitializer
  %r = frem <2 x float> %splat, <float 4.200000e+01, float 4.200000e+01>
  ret <2 x float> %r
}

define <2 x i32> @not_splat_shuffle2(i32 %x) {
  %vec = insertelement <2 x i32> poison, i32 %x, i32 1
  %shuf = shufflevector <2 x i32> %vec, <2 x i32> undef, <2 x i32> <i32 1, i32 3>
  ret <2 x i32> %shuf
}

define <2 x float> @uitofp_shuf_narrow(<4 x i32> %x, <4 x i32> %y) {
  %nx = uitofp <4 x i32> %x to <4 x float>
  %ny = uitofp <4 x i32> %y to <4 x float>
  %r = shufflevector <4 x float> %nx, <4 x float> %ny, <2 x i32> <i32 3, i32 5>
  ret <2 x float> %r
}
